import { DatePipe, DOCUMENT } from "@angular/common";
import { HttpClient } from "@angular/common/http";
import { Component, ElementRef, Inject, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { ActivatedRoute, Router } from "@angular/router";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { ThemeService } from "src/app/core/services/theme.service";
import { LoginResponse } from "../../Models/Settings/LoginResponse";
import { App } from "@capacitor/app";
import { Platform, AlertController } from "@ionic/angular";
import { Subscription } from "rxjs";
import { AccessRight } from "../../Models/Permissions/AccessRight";
import { MENU } from "../../layout/sidebar/menu";
import { LocationService } from "src/app/core/services/location.service";
import { Capacitor } from "@capacitor/core";
import { CameraService } from "src/app/core/services/camera.service";
import { pagingService } from "src/app/core/services/paging.service";
import { UserBranchInfo } from "../../Models/Users/User";
import { UserService } from "src/app/core/services/user.service";
import { Preferences } from "@capacitor/preferences";
import { InputMaskingService } from "src/app/core/services/input-masking.service";

@Component({
  selector: "app-login",
  templateUrl: "./login.page.html",
  styleUrls: ["./login.page.scss"],
})
export class LoginPage {
  backButtonListener: Subscription;
  showLoader: boolean = false;
  isLoggedIn: boolean = false;
  shouldChangePassword: boolean = false;
  isSubmitted: boolean = false;
  errorMessage: string = null;
  userBranchInfo: UserBranchInfo;
  openOtp = false;

  loginForm: FormGroup = this.formBuilder.group({
    // serviceUrl: ["", [Validators.required]],
    username: ["", [Validators.required]],
    password: ["", [Validators.required]],
  });

  otpForm: FormGroup = this.formBuilder.group({
    firstField: [
      "",
      [Validators.required, Validators.min(0), Validators.max(99)],
    ],
    secondField: [
      "",
      [Validators.required, Validators.min(0), Validators.max(99)],
    ],
    thirdField: [
      "",
      [Validators.required, Validators.min(0), Validators.max(99)],
    ],
    fourthField: [
      "",
      [Validators.required, Validators.min(0), Validators.max(99)],
    ],
  });

  constructor(
    private formBuilder: FormBuilder,
    private authService: MohassilAuthService,
    private cameraService: CameraService,
    private http: HttpClient,
    private envService: EnvService,
    private router: Router,
    private activatedRoute: ActivatedRoute,
    @Inject(DOCUMENT) private document: Document,
    public themeService: ThemeService,
    private platform: Platform,
    private alertController: AlertController,
    private location: LocationService,
    private pagingService: pagingService,
    private elRef: ElementRef,
    private datePipe: DatePipe,
    public inputMaskingService: InputMaskingService,
    private userService: UserService
  ) {}

  async ionViewWillEnter() {
    // check if logged in already and redirect
    this.registerBackButtonListener();
    this.updateTheme();
    await this.checkForLogout();
    await this.initializeForm();
    this.elRef.nativeElement.addEventListener(
      "keydown",
      this.handleKeyDown.bind(this)
    );
  }

  ionViewWillLeave(): void {
    this.backButtonListener.unsubscribe();
    this.elRef.nativeElement.removeEventListener(
      "keydown",
      this.handleKeyDown.bind(this)
    );
  }

  handleKeyDown(event: KeyboardEvent) {
    if (event.key === "Enter") {
      this.onSubmit();
    }
  }

  registerBackButtonListener(): void {
    this.backButtonListener = this.platform.backButton.subscribeWithPriority(
      0,
      (next) => {
        this.exitAlert();
      }
    );
  }

  async exitAlert(): Promise<void> {
    let alert = this.alertController.create({
      header: "الخروج",
      message: "هل انت متأكد من الخروج من البرنامج؟",
      buttons: [
        {
          text: "نعم",
          role: "OK",
          cssClass: "alert-button-confirm",
          handler: () => {
            App.exitApp();
          },
        },
        {
          text: "لا",
          cssClass: "alert-button-confirm",
          role: "cancel",
          handler: () => {},
        },
      ],
    });
    (await alert).present();
  }

  updateTheme(): void {
    if (this.themeService.isDarkMode) {
      this.document.body.classList.add("darkmode");
    } else {
      this.document.body.classList.remove("darkmode");
    }
  }

  async checkForLogout(): Promise<void> {
    let params = this.activatedRoute.snapshot.queryParams;
    if (!!params["logout"] && params["logout"] == "true") {
      this.resetLoginForm();
      this.resetOtpForm();
    }
  }

  async initializeForm(): Promise<void> {
    // // TESTING FOR FINBI
    // const serviceUrl: URL = new URL("http://41.33.180.141:8010");
    // await this.authService.setServiceUrl(serviceUrl);
    // this.loginForm.patchValue({
    //   serviceUrl: serviceUrl,
    // });
    // let serviceUrl = await this.authService.getServiceUrl();
    // if (!!serviceUrl && serviceUrl != "") {
    //   this.loginForm.patchValue({
    //     serviceUrl: serviceUrl,
    //   });
    // }
  }

  async resetLoginForm(): Promise<void> {
    this.isSubmitted = false;
    let otpToken = await this.authService.getOtpToken();
    this.openOtp = !!otpToken;
    this.errorMessage = null;
    this.loginForm.patchValue({
      username: "",
      password: "",
    });
  }

  async resetOtpForm(): Promise<void> {
    this.isSubmitted = false;
    let otpToken = await this.authService.getOtpToken();
    this.openOtp = !!otpToken;
    this.errorMessage = null;
    this.otpForm.patchValue({
      firstField: "",
      secondField: "",
      thirdField: "",
      fourthField: "",
    });
  }

  // async saveServiceUrl(): Promise<void> {
  //   const currentServiceUrl: string =
  //     this.loginForm.get("serviceUrl").value ?? "";
  //   await this.authService.setServiceUrl(currentServiceUrl);
  // }

  async onSubmit(): Promise<void> {
    this.isSubmitted = true;
    if (!this.loginForm.valid) {
      // if (this.loginForm.get("serviceUrl").hasError("required")) {
      //   this.errorMessage = "تأكد من كتابة عنوان الخدمة";
      // }
      return;
    }
    this.showLoader = true;
    let serviceUrl: URL;
    try {
      serviceUrl = new URL(this.envService.API_URL);
    } catch (error) {
      this.errorMessage = "عنوان الخادم غير سليم، برجاء الرجوع لمشرف النظام";
      return;
    }
    let username: string = this.loginForm.get("username").value;
    let password: string = this.loginForm.get("password").value;
    try {
      let response = await this.authService.login(username, password);
      if (typeof response === "boolean") {
        this.shouldChangePassword = !response;
        this.openOtp = false;
      } else {
        this.shouldChangePassword = false;
        this.openOtp = response.twoFactorAuth;
      }
      this.errorMessage = "";
    } catch (err) {
      this.errorMessage = err;
    }
    this.showLoader = false;
  }
  async onSubmitOtp(): Promise<void> {
    this.isSubmitted = true;
    if (!this.otpForm.valid) {
      this.errorMessage = "يجب أن تكون حقول OTP بين 0 و 99";
      return;
    }
    this.showLoader = true;
    let serviceUrl: URL;
    try {
      serviceUrl = new URL(this.envService.API_URL);
    } catch (error) {
      this.errorMessage = "عنوان الخادم غير سليم، برجاء الرجوع لمشرف النظام";
      return;
    }
    let first: string = this.otpForm.get("firstField").value;
    let second: string = this.otpForm.get("secondField").value;
    let third: string = this.otpForm.get("thirdField").value;
    let fourth: string = this.otpForm.get("fourthField").value;

    let otp = `${first}/${second}/${third}/${fourth}`;
    try {
      let response = await this.authService.sendOtp(otp);
      this.errorMessage = "";
    } catch (err) {
      this.errorMessage = err;
    }
    this.showLoader = false;
  }
}
